mapper.select:
/* wms-outbound-obAllocateRelease-sql-oracle.xml - selectManualObDt - WMS > 출고 관리 > 할당(RELEASE) > 수동할당 - 할당 가능 상태 확인 */ SELECT OD.CTKEY /*센터코드*/ , OD.OWKEY /*화주코드*/ , OD.OBHDKEY /*릴리즈코드*/ , OD.OBDTKEY /*릴리즈상세코드*/ , COALESCE(MAX(AD.ALSEQ), 0) + 1 AS ALSEQ /*할당순번*/ , 'H' AS ALDIVCD /*할당구분코드*/ , IVATX.IVATKEY /*재고속성코드*/ , IVATX.LCKEY /*로케이션코드*/ , IVATX.LCKEY AS CELLKEY /*셀코드*/ , OD.ICKEY /*상품코드*/ , OD.UOM /*상품단위유형*/ , #{mvqty} ALQTY /*할당수량*/ , '' AS ALSTRGID /*할당전략아이디*/ , '' AS PIHDKEY /*피킹헤더코드*/ , '' AS PIDTKEY /*피킹상세코드*/ FROM TWORK_INFO_OB_HD OH INNER JOIN TWORK_INFO_OB_DT OD ON OH.CTKEY = OD.CTKEY AND OH.OWKEY = OD.OWKEY AND OH.OBHDKEY = OD.OBHDKEY INNER JOIN TWORK_INFO_IVATXLC IVATX ON OD.CTKEY = IVATX.CTKEY AND OD.OWKEY = IVATX.OWKEY AND OD.ICKEY = IVATX.ICKEY AND IVATX.IVSTATUSCD = '10' INNER JOIN TWORK_MST_LC LC ON IVATX.CTKEY = LC.CTKEY AND IVATX.LCKEY = LC.LCKEY LEFT OUTER JOIN TWORK_INFO_AL_DT AD ON OD.CTKEY = AD.CTKEY AND OD.OWKEY = AD.OWKEY AND OD.OBHDKEY = AD.OBHDKEY AND OD.OBDTKEY = AD.OBDTKEY INNER JOIN TWORK_MST_LC LC ON IVATX.CTKEY = LC.CTKEY AND IVATX.LCKEY = LC.LCKEY INNER JOIN TWORK_MST_AR AR ON LC.CTKEY = AR.CTKEY AND LC.ARKEY = AR.ARKEY INNER JOIN TWORK_MST_ZN ZN ON AR.CTKEY = ZN.CTKEY AND AR.ZNKEY = ZN.ZNKEY WHERE OH.CTKEY = #{ctkey} AND OH.OWKEY = #{owkey} AND OH.OBHDKEY = #{obhdkey} AND OD.OBDTKEY = #{obdtkey} AND COALESCE(LC.LCLIMITDIVCD, '00') NOT IN ('20','40') AND IVATX.LCKEY = #{lckey} AND IVATX.IVATKEY = #{ivatkey} AND OD.EXPCTQTY > OD.ALQTY AND IVATX.AVQTY >= #{mvqty}
AND (LC.LCTYPECD = '90' /*보관 로케이션*/ OR ZN.ZNKEY = 'MLD' /*B2B이고대기구역*/)
AND LC.LCTYPECD = '90' /*보관 로케이션*/
GROUP BY OD.CTKEY /*센터코드*/ , OD.OWKEY /*화주코드*/ , OD.OBHDKEY /*릴리즈코드*/ , OD.OBDTKEY /*릴리즈상세코드*/ , IVATX.IVATKEY /*재고속성코드*/ , IVATX.LCKEY /*로케이션코드*/ , OD.ICKEY /*상품코드*/ , OD.UOM /*상품단위유형*/

mapper.update:
/* wms-outbound-obAllocateReleaseManager-sql-oracle.xml - updateManualObdt - 출고 관리 > 할당(RELEASE) > 수동할당 - 릴리즈 상세 update */
UPDATE TWORK_INFO_OB_DT
   SET OBDTSTATUSCD = (CASE WHEN OBDTSTATUSCD IN ('00','05') THEN (CASE WHEN EXPCTQTY > ALQTY + #{alqty} THEN '05' ELSE '10' END) ELSE OBDTSTATUSCD END)
	 , ALQTY = ALQTY + COALESCE(#{alqty}, 0)
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBHDKEY = #{obhdkey}
   AND OBDTKEY = #{obdtkey}

mapper.delete:
/* wms-outbound-obAllocateReleaseManager-sql-oracle.xml - deleteCancelProcAl - 출고 관리 > 할당(RELEASE) > 할당취소 - 할당데이터 삭제 */
DELETE FROM TWORK_INFO_AL_DT
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBHDKEY = #{obhdkey}
   AND OBDTKEY = #{obdtkey}
   AND ALSEQ = #{alseq}

mapper.select:
/* wms-outbound-obAllocateReleaseManager-sql-oracle.xml - selectIvatxLockByAllocate - 출고 관리 > 할당(RELEASE) > 할당취소 - 할당처리를 위한 재고 LOCK */
SELECT CTKEY
	, OWKEY
	, IVATKEY
	, LCKEY
	, ICKEY
	, IVSERIALNO
FROM TWORK_INFO_IVATXLC
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND ICKEY = #{ickey}
AND IVATKEY = #{ivatkey}
AND LCKEY = #{lckey}
AND TOTQTY > 0
FOR UPDATE

mapper.update:
/* wms-outbound-obAllocateReleaseManager-sql-oracle.xml - updateCancelProcObDt - 출고 관리 > 할당(RELEASE) > 할당취소 - 릴리즈 상세 업데이트 */
UPDATE TWORK_INFO_OB_DT
   SET OBDTSTATUSCD = (CASE WHEN ALQTY - COALESCE(#{alqty}, 0) = 0 THEN '00' WHEN EXPCTQTY > ALQTY + COALESCE(#{alqty}, 0) THEN '05' ELSE OBDTSTATUSCD END)
	 , ALQTY = ALQTY - COALESCE(#{alqty}, 0)
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBHDKEY = #{obhdkey}
   AND OBDTKEY = #{obdtkey}

/* wms-outbound-obAllocateReleaseManager-sql-oracle.xml - updateStockOutProcObDt - 출고 관리 > 할당(RELEASE) > 미할당처리 - 릴리즈 상세 업데이트 */
UPDATE TWORK_INFO_OB_DT
   SET OBDTSTATUSCD = #{obdtstatuscd}
	 , EXPCTQTY = EXPCTQTY - #{stockOutQty}
	 , NISQTY = NISQTY + #{stockOutQty}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBHDKEY = #{obhdkey}
   AND OBDTKEY = #{obdtkey}

mapper.sql:
SELECT IVATX.CTKEY , IVATX.OWKEY , IVATX.ICKEY , IVATX.IVATKEY , IVATX.LCKEY , IVATX.AVQTY , #{expctqty} AS EXPCTQTY , ROW_NUMBER() OVER (
${item.atvalue1} ${item.atvalue2}
) AS RN FROM TWORK_INFO_IVATXLC IVATX INNER JOIN TWORK_INFO_IVAT IVAT ON IVATX.CTKEY = IVAT.CTKEY AND IVATX.OWKEY = IVAT.OWKEY AND IVATX.ICKEY = IVAT.ICKEY AND IVATX.IVATKEY = IVAT.IVATKEY WHERE (IVATX.CTKEY, IVATX.OWKEY, IVATX.IVATKEY, IVATX.LCKEY, IVATX.ICKEY, IVATX.IVSERIALNO) IN
(#{item.ctkey}, #{item.owkey}, #{item.ivatkey}, #{item.lckey}, #{item.ickey}, #{item.ivserialno})

mapper.select:
/* wms-outbound-obAllocateReleaseManager-sql-oracle.xml - selectIvatxRowIdList - WMS > 출고 관리 > 할당(RELEASE) > 자동할당 - 재고 ROWID 조회 */
SELECT
	IVATX.CTKEY
	,IVATX.OWKEY
	,IVATX.IVATKEY
	,IVATX.LCKEY
	,IVATX.ICKEY
	,IVATX.IVSERIALNO
	/*ROWIDTOCHAR(IVATX.ROWID) AS RID*/
FROM TWORK_INFO_IVATXLC IVATX
	 INNER JOIN TWORK_INFO_IVAT IVAT
		ON IVATX.CTKEY = IVAT.CTKEY
	   AND IVATX.OWKEY = IVAT.OWKEY
	   AND IVATX.ICKEY = IVAT.ICKEY
	   AND IVATX.IVATKEY = IVAT.IVATKEY
	 INNER JOIN TWORK_MST_IC IC
		ON IVATX.CTKEY = IC.CTKEY
	   AND IVATX.OWKEY = IC.OWKEY
	   AND IVATX.ICKEY = IC.ICKEY
	 INNER JOIN TWORK_MST_LC LC
		ON IVATX.CTKEY = LC.CTKEY
	   AND IVATX.LCKEY = LC.LCKEY
	 WHERE IVATX.CTKEY = #{ctkey}
	   AND IVATX.OWKEY = #{owkey}
	   AND IVATX.ICKEY = #{ickey}
	   AND IVATX.IVSTATUSCD = '10'
	   AND IVATX.AVQTY > 0
	   AND COALESCE(LC.LCLIMITDIVCD, '00') NOT IN ('20','40')
	   AND (CASE WHEN COALESCE(IC.EXPCKTYPECD, ' ')  <>  'E' THEN TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDD')
				ELSE TO_CHAR(TO_DATE(SUBSTR(IVAT.EXPDATE,1,8),'YYYYMMDD') - IC.EXPCNVRSNDAYS::INTEGER + TRUNC(IC.EXPCNVRSNDAYS * (IC.OBIMPSCRITRT / 100))::INTEGER,'YYYYMMDD')
		   END) >= TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDD')
	   AND (
				(


