					/*WHERE - 50(특정 로케이션 제외)*/

						#{item.atvalue1}





					/*WHERE - 60(특정 구역 제외)*/

						#{item.atvalue1}



				)


				/*30(특정 로케이션 포함)*/

					#{item.atvalue1}





				/*40(특정 구역 포함)*/

					#{item.atvalue1}



		   )

/* wms-outbound-obAllocateReleaseManager-sql-oracle.xml - selectIvatxLockByRowIdList - WMS > 출고 관리 > 할당(RELEASE) > 자동할당 - 재고 ROWID 조회 */ SELECT CTKEY , OWKEY , IVATKEY , LCKEY , ICKEY , IVSERIALNO FROM TWORK_INFO_IVATXLC WHERE (CTKEY, OWKEY, IVATKEY, LCKEY, ICKEY, IVSERIALNO) IN
(#{item.ctkey}, #{item.owkey}, #{item.ivatkey}, #{item.lckey}, #{item.ickey}, #{item.ivserialno})
