mapper.sql:
SELECT IVATX.CTKEY , IVATX.OWKEY , IVATX.ICKEY , IVATX.IVATKEY , IVATX.LCKEY , IVATX.AVQTY , #{expctqty} AS EXPCTQTY , ROW_NUMBER() OVER (ORDER BY IVATX.IVATKEY) AS RN FROM TWORK_INFO_IVATXLC IVATX INNER JOIN TWORK_INFO_IVAT IVAT ON IVATX.CTKEY = IVAT.CTKEY AND IVATX.OWKEY = IVAT.OWKEY AND IVATX.ICKEY = IVAT.ICKEY AND IVATX.IVATKEY = IVAT.IVATKEY WHERE 1=1
#{item.rid}
ORDER BY IVAT.EXPDATE , IVATX.LCKEY

mapper.update:
/* wms-outbound-ObOrdSepManagerMapper-sql-oracle.xml - updateAutoProcObDt - WMS > 출고 관리 >할당(RELEASE) > 이고할당 - 릴리즈 상세 업데이트 */
UPDATE TWORK_INFO_OB_DT
   SET OBDTSTATUSCD = (CASE WHEN OBDTSTATUSCD IN ('00','05') THEN (CASE WHEN EXPCTQTY > ALQTY + COALESCE(#{alqty}, 0) THEN '05' ELSE '10' END) ELSE OBDTSTATUSCD END)
	 , ALQTY = ALQTY + COALESCE(#{alqty}, 0)
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBHDKEY = #{obhdkey}
   AND ICKEY = #{ickey}

/* wms-outbound-obAllocateReleaseManager-sql-oracle.xml - updateIvatRedt - WMS > 출고 관리 > 할당(RELEASE) : 재고 수량 차감 */
UPDATE TWORK_INFO_IVATXLC
   SET AVQTY = AVQTY - COALESCE(#{alqty}, 0)
	 , ALQTY = ALQTY + COALESCE(#{alqty}, 0)
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND ICKEY = #{ickey}
   AND IVATKEY = #{ivatkey}
   AND LCKEY = #{lckey}
   AND COALESCE(#{alqty}, 0)  <=  AVQTY

/* wms-outbound-obAllocateReleaseManager-sql-oracle.xml - updateIvatIncr - 출고 관리 > 할당(RELEASE) : 재고 수량 증가 */
UPDATE TWORK_INFO_IVATXLC
   SET AVQTY = AVQTY + COALESCE(#{alqty}, 0)
	 , ALQTY = ALQTY - COALESCE(#{alqty}, 0)
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND ICKEY = #{ickey}
   AND IVATKEY = #{ivatkey}
   AND LCKEY = #{lckey}
   AND COALESCE(#{alqty}, 0)  <=  ALQTY
